import React, { useEffect, useState } from "react";
import Navbar from "../components/Navbar";
import api from "../services/api";

function AddMealPage() {
  const [foods, setFoods] = useState([]);
  const [meals, setMeals] = useState([]);

  const [mealForm, setMealForm] = useState({
    meal_date: "",
    meal_type: "Sáng",
    meal_time: "",
    note: ""
  });

  const [foodForm, setFoodForm] = useState({
    meal_id: "",
    food_id: "",
    quantity_g: ""
  });

  const loadFoods = async () => {
    try {
      const res = await api.get("/foods");
      setFoods(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  const loadMeals = async () => {
    try {
      const res = await api.get("/meals");
      setMeals(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  useEffect(() => {
    loadFoods();
    loadMeals();
  }, []);

  const handleMealChange = (e) => {
    setMealForm({ ...mealForm, [e.target.name]: e.target.value });
  };

  const handleFoodChange = (e) => {
    setFoodForm({ ...foodForm, [e.target.name]: e.target.value });
  };

  const createMeal = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post("/meals", mealForm);
      alert(res.data.message);
      loadMeals();
    } catch (err) {
      alert(err.response?.data?.error || "Lỗi tạo bữa ăn");
    }
  };

  const addFood = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post("/nutrition-logs", foodForm);
      alert(res.data.message);
    } catch (err) {
      alert(err.response?.data?.error || "Lỗi thêm đồ ăn");
    }
  };

  return (
    <div>
      <Navbar />
      <div className="page-container">
        <h2>Thêm đồ ăn</h2>

        <div className="card">
          <h3>Tạo bữa ăn</h3>
          <form onSubmit={createMeal}>
            <input type="date" name="meal_date" value={mealForm.meal_date} onChange={handleMealChange} />
            <br /><br />

            <select name="meal_type" value={mealForm.meal_type} onChange={handleMealChange}>
              <option value="Sáng">Sáng</option>
              <option value="Trưa">Trưa</option>
              <option value="Tối">Tối</option>
              <option value="Phụ">Phụ</option>
            </select>
            <br /><br />

            <input type="time" name="meal_time" value={mealForm.meal_time} onChange={handleMealChange} />
            <br /><br />

            <input type="text" name="note" placeholder="Ghi chú" value={mealForm.note} onChange={handleMealChange} />
            <br /><br />

            <button type="submit">Tạo bữa ăn</button>
          </form>
        </div>

        <div className="card">
          <h3>Thêm đồ ăn vào bữa</h3>
          <form onSubmit={addFood}>
            <select name="meal_id" value={foodForm.meal_id} onChange={handleFoodChange}>
              <option value="">Chọn bữa ăn</option>
              {meals.map((meal) => (
                <option key={meal.meal_id} value={meal.meal_id}>
                  {meal.meal_date} - {meal.meal_type} - {meal.meal_time}
                </option>
              ))}
            </select>
            <br /><br />

            <select name="food_id" value={foodForm.food_id} onChange={handleFoodChange}>
              <option value="">Chọn thực phẩm</option>
              {foods.map((food) => (
                <option key={food.food_id} value={food.food_id}>
                  {food.food_name}
                </option>
              ))}
            </select>
            <br /><br />

            <input
              type="number"
              name="quantity_g"
              placeholder="Khối lượng (g)"
              value={foodForm.quantity_g}
              onChange={handleFoodChange}
            />
            <br /><br />

            <button type="submit">Thêm đồ ăn</button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default AddMealPage;
